{"method":"get_file","path":"templates/app/DashboardScreen.jsx","content":"// DataQ — Dashboard (Enhanced Monitoring). The post-login landing: KPI
// row, a dark Quality Trends chart, Suite Performance gauges, and a
// Recent Runs table. Composed from design-system components.
const DQd = window.DataQDesignSystem_317fec;

function Legend({ color, label }) {
  return (
    <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6, fontSize: 13, color: 'rgba(255,255,255,0.85)' }}>
      <span style={{ width: 9, height: 9, borderRadius: '50%', background: color }} />{label}
    </span>
  );
}

function QualityTrends() {
  const bars = [
    { h: 52 }, { h: 68 }, { h: 60 }, { h: 88 }, { h: 30, fail: true }, { h: 74 },
    { h: 82 }, { h: 56 }, { h: 80 }, { h: 22, fail: true }, { h: 70 }, { h: 90 },
  ];
  const labels = ['Jun 02', 'Jun 05', 'Jun 08', 'Jun 11', 'Jun 13'];
  return (
    <DQd.Card tone="dark" padding={24}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div>
          <div style={{ fontSize: 20, fontWeight: 700, color: '#fff' }}>Quality Trends</div>
          <div style={{ fontSize: 13, color: 'var(--text-on-dark-dim)', marginTop: 4 }}>Pass vs fail executions · last 14 days</div>
        </div>
        <div style={{ display: 'flex', gap: 16 }}>
          <Legend color="var(--indigo-400)" label="Pass" />
          <Legend color="var(--red-500)" label="Fail" />
        </div>
      </div>
      <div style={{ display: 'flex', alignItems: 'flex-end', gap: 8, height: 168, marginTop: 24 }}>
        {bars.map((b, i) => (
          <div key={i} style={{
            flex: 1, height: `${b.h}%`, borderRadius: '4px 4px 0 0',
            background: b.fail ? 'color-mix(in srgb, var(--red-500) 78%, var(--ink))' : 'color-mix(in srgb, var(--indigo-500) 62%, var(--ink))',
            borderTop: `2px solid ${b.fail ? 'var(--red-500)' : 'var(--indigo-400)'}`,
          }} />
        ))}
      </div>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 12, paddingTop: 10, borderTop: '1px solid rgba(255,255,255,0.08)' }}>
        {labels.map((l) => <span key={l} style={{ fontSize: 11, fontFamily: 'var(--font-mono)', color: 'rgba(255,255,255,0.4)' }}>{l}</span>)}
      </div>
    </DQd.Card>
  );
}

function SuitePerformance() {
  const { Card, ProgressBar } = DQd;
  const rows = [
    { name: 'Financial Transactions', state: 'Optimal', value: 96, tone: 'pass' },
    { name: 'User Metadata', state: 'Stable', value: 74, tone: 'warning' },
    { name: 'Real-time Telemetry', state: 'Critical', value: 34, tone: 'fail' },
    { name: 'Audit Logs', state: 'Optimal', value: 92, tone: 'pass' },
  ];
  const stateColor = { Optimal: 'var(--status-pass)', Stable: 'var(--status-warn)', Critical: 'var(--status-fail)' };
  return (
    <Card padding={24}>
      <div style={{ fontSize: 20, fontWeight: 700, color: 'var(--text-primary)' }}>Suite Performance</div>
      <div style={{ fontSize: 13, color: 'var(--text-muted)', marginTop: 4 }}>Health by category</div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 18, marginTop: 22 }}>
        {rows.map((r) => (
          <div key={r.name}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8 }}>
              <span style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)' }}>{r.name}</span>
              <span style={{ fontSize: 13, fontWeight: 600, color: stateColor[r.state] }}>{r.state}</span>
            </div>
            <ProgressBar value={r.value} tone={r.tone} height={8} />
          </div>
        ))}
      </div>
    </Card>
  );
}

function RecentRuns({ onOpen }) {
  const { Card, DataTable, StatusBadge, Button, IconButton } = DQd;
  const rows = [
    { suite: 'Daily Revenue Audit', conn: 'Snowflake_Prod_01', status: 'succeeded', anomalies: 0, time: '12m ago', by: 'adf:daily_load:9f2', started: 'Jun 13, 09:12', dur: '12m 45s' },
    { suite: 'Customer Ingestion Flow', conn: 'AWS_S3_Landing', status: 'failed', anomalies: 42, time: '45m ago', by: 'airflow:cust_dag:7a1', started: 'Jun 13, 08:30', dur: '45m 12s' },
    { suite: 'ML Feature Store', conn: 'Databricks_UC_Main', status: 'running', anomalies: 3, time: '1h ago', by: 'manual', started: 'Jun 13, 10:02', dur: '—' },
    { suite: 'GDPR Compliance Check', conn: 'Postgres_EU_West', status: 'succeeded', anomalies: 0, time: '2h ago', by: 'schedule', started: 'Jun 13, 06:00', dur: '3m 08s' },
  ];
  const cols = [
    { key: 'suite', header: 'Suite', render: (v) => <strong style={{ color: 'var(--text-primary)', fontWeight: 600 }}>{v}</strong> },
    { key: 'conn', header: 'Connection', mono: true, render: (v) => <span style={{ color: 'var(--text-accent)' }}>{v}</span> },
    { key: 'status', header: 'Status', width: 130, render: (v) => <StatusBadge status={v} variant="soft" /> },
    { key: 'anomalies', header: 'Anomalies', align: 'right', render: (v) => <span style={{ fontWeight: 700, color: v > 0 ? 'var(--status-fail)' : 'var(--text-body)' }}>{v}</span> },
    { key: 'time', header: 'When', nowrap: true, render: (v) => <span style={{ color: 'var(--text-muted)' }}>{v}</span> },
    { key: 'act', header: '', align: 'right', render: () => <Button variant="ghost" size="sm">View</Button> },
  ];
  return (
    <Card padding={0} style={{ overflow: 'hidden' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '18px 20px 14px' }}>
        <span style={{ fontSize: 18, fontWeight: 700, color: 'var(--text-primary)' }}>Recent Runs</span>
        <IconButton ariaLabel="Refresh"><window.Icon.refresh size={16} /></IconButton>
      </div>
      <DataTable columns={cols} rows={rows} onRowClick={(r) => onOpen && onOpen(r)} />
    </Card>
  );
}

function DashboardScreen({ go }) {
  const { MetricCard, SegmentedControl } = DQd;
  const I = window.Icon;
  const [range, setRange] = React.useState('7d');
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 20, maxWidth: 1200, margin: '0 auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <h1 style={{ margin: 0, fontSize: 24, fontWeight: 600, color: 'var(--text-primary)' }}>Monitoring Dashboard</h1>
          <div style={{ fontSize: 14, color: 'var(--text-secondary)', marginTop: 4 }}>Welcome back, Jane — here's your workspace health.</div>
        </div>
        <SegmentedControl options={['Last 24h', '7d', '30d']} value={range} onChange={setRange} />
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 16 }}>
        <MetricCard label="Data Integrity Score" value="99.8%" delta="+0.4%" trend="up" icon={<I.shield size={18} />} progress={99.8} />
        <MetricCard label="Total Anomalies" value="128" delta="-14%" trend="down" icon={<I.alert size={18} />} footnote="Last 7 days cumulative" />
        <MetricCard label="Active Connections" value="14" unit="operational" icon={<I.connections size={18} />} progress={88} />
        <MetricCard label="Avg. Time to Resolution" value="2.4h" delta="-20m" trend="down" icon={<I.clock size={18} />} />
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1.55fr 1fr', gap: 16 }}>
        <QualityTrends />
        <SuitePerformance />
      </div>
      <RecentRuns onOpen={(run) => go && go('run-detail', { run })} />
    </div>
  );
}

Object.assign(window, { DashboardScreen });
