// DataQ — Results page. Mirrors the shipped /results surface: summary
// health widgets (Week-6 planned) + Runs / Pipeline-runs tabs on antd
// Tables. Composes MetricCard, DataTable, StatusBadge, Tag.
const DQ = window.DataQDesignSystem_317fec;

function Tabs({ value, onChange, items }) {
  return (
    <div style={{ display: 'flex', gap: 24, borderBottom: '1px solid var(--border)', marginBottom: 4 }}>
      {items.map((it) => {
        const active = it.key === value;
        return (
          <button key={it.key} onClick={() => onChange(it.key)} style={{
            background: 'none', border: 'none', cursor: 'pointer', padding: '10px 2px',
            fontFamily: 'var(--font-sans)', fontSize: 14, fontWeight: active ? 600 : 500,
            color: active ? 'var(--indigo-600)' : 'var(--text-secondary)',
            borderBottom: `2px solid ${active ? 'var(--indigo-600)' : 'transparent'}`, marginBottom: -1,
          }}>{it.label}</button>
        );
      })}
    </div>
  );
}

const RUNS = [
  { suite: 'Daily Revenue Audit', status: 'succeeded', by: 'adf:daily_load:9f2', started: 'Jun 13, 09:12', dur: '12m 45s' },
  { suite: 'Customer Ingestion Flow', status: 'failed', by: 'airflow:cust_dag:7a1', started: 'Jun 13, 08:30', dur: '45m 12s' },
  { suite: 'ML Feature Store', status: 'running', by: 'manual', started: 'Jun 13, 10:02', dur: '—' },
  { suite: 'GDPR Compliance Check', status: 'succeeded', by: 'schedule', started: 'Jun 13, 06:00', dur: '3m 08s' },
  { suite: 'Warehouse Reconciliation', status: 'cancelled', by: 'manual', started: 'Jun 12, 22:14', dur: '—' },
];

const PIPELINES = [
  { provider: 'adf', dag: 'adf-daily-ingest', env: 'PROD', status: 'succeeded', started: 'Jun 13, 09:00', reason: '—' },
  { provider: 'airflow', dag: 'cust_ingestion_dag', env: 'PROD', status: 'failed', started: 'Jun 13, 08:25', reason: 'Task retry limit exceeded' },
  { provider: 'adf', dag: 'adf-uc-sync', env: 'UAT', status: 'running', started: 'Jun 13, 10:00', reason: '—' },
  { provider: 'airflow', dag: 'feature_store_dag', env: 'QA', status: 'succeeded', started: 'Jun 13, 02:00', reason: '—' },
];

function RunsTab({ onOpen }) {
  const { DataTable, StatusBadge } = DQ;
  const cols = [
    { key: 'suite', header: 'Suite', render: (v) => <strong style={{ color: 'var(--text-primary)', fontWeight: 600 }}>{v}</strong> },
    { key: 'status', header: 'Status', width: 130, render: (v) => <StatusBadge status={v} variant="soft" /> },
    { key: 'by', header: 'Triggered by', mono: true, render: (v) => <span style={{ color: 'var(--text-accent)' }}>{v}</span> },
    { key: 'started', header: 'Started', nowrap: true },
    { key: 'dur', header: 'Duration', align: 'right', nowrap: true, render: (v) => <span style={{ color: 'var(--text-muted)' }}>{v}</span> },
  ];
  return <DQ.Card padding={0} style={{ overflow: 'hidden' }}><DataTable columns={cols} rows={RUNS} onRowClick={(r) => onOpen(r)} /></DQ.Card>;
}

const CHECK_RESULTS = [
  { check: 'revenue not null', exp: 'expect_column_values_to_not_be_null', status: 'pass', metric: '0.0', observed: '0 unexpected' },
  { check: 'amount positive', exp: 'expect_column_values_to_be_between', status: 'pass', metric: '0.0', observed: 'min 0.01' },
  { check: 'email format', exp: 'expect_column_values_to_match_regex', status: 'fail', metric: '4.2', observed: '412 / 9842' },
  { check: 'customer id unique', exp: 'expect_column_values_to_be_unique', status: 'critical', metric: '11.8', observed: '1,160 dupes' },
  { check: 'row count stable', exp: 'expect_table_row_count_to_be_between', status: 'warn', metric: '1.0', observed: '9,842 rows' },
];

function Meta({ label, children }) {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
      <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>{label}</span>
      <span style={{ fontSize: 14, color: 'var(--text-primary)', fontWeight: 500 }}>{children}</span>
    </div>
  );
}

function DownloadMenu({ run }) {
  const { Button } = DQ;
  const [open, setOpen] = React.useState(false);
  const ref = React.useRef(null);

  React.useEffect(() => {
    if (!open) return undefined;
    const onDoc = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener('mousedown', onDoc);
    return () => document.removeEventListener('mousedown', onDoc);
  }, [open]);

  const slug = (run.suite || 'run').toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '');

  const triggerDownload = (filename, mime, text) => {
    const blob = new Blob([text], { type: mime });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = filename;
    document.body.appendChild(a); a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 0);
    setOpen(false);
  };

  const downloadCsv = () => {
    const cols = ['check', 'exp', 'status', 'metric', 'observed'];
    const head = ['Check', 'Expectation', 'Status', 'Metric', 'Observed'];
    const esc = (v) => { const s = String(v == null ? '' : v); return /[",\n]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s; };
    const lines = [head.join(',')].concat(CHECK_RESULTS.map((r) => cols.map((c) => esc(r[c])).join(',')));
    triggerDownload(`${slug}_results.csv`, 'text/csv;charset=utf-8', lines.join('\n'));
  };

  const downloadJson = () => {
    const payload = {
      suite: run.suite, triggeredBy: run.by, status: run.status,
      started: run.started, duration: run.dur,
      checks: CHECK_RESULTS.map((r) => ({ name: r.check, expectation: r.exp, status: r.status, metric: r.metric, observed: r.observed })),
    };
    triggerDownload(`${slug}_results.json`, 'application/json', JSON.stringify(payload, null, 2));
  };

  const Item = ({ icon, label, onClick }) => {
    const [hover, setHover] = React.useState(false);
    return (
      <button onMouseDown={onClick}
        onMouseEnter={() => setHover(true)} onMouseLeave={() => setHover(false)}
        style={{
          display: 'flex', alignItems: 'center', gap: 10, width: '100%', textAlign: 'left',
          padding: '8px 12px', border: 'none', borderRadius: 'var(--radius)', cursor: 'pointer',
          background: hover ? 'var(--bg-hover)' : 'transparent',
          fontFamily: 'var(--font-sans)', fontSize: 13, fontWeight: 500, color: 'var(--text-body)',
        }}>
        <span style={{ color: 'var(--text-muted)', display: 'inline-flex' }}>{icon}</span>{label}
      </button>
    );
  };

  return (
    <div ref={ref} style={{ position: 'relative' }}>
      <Button variant="secondary" size="sm"
        iconLeft={<window.Icon.download size={14} />}
        iconRight={<window.Icon.down size={11} style={{ marginLeft: -2 }} />}
        onClick={() => setOpen((o) => !o)}>Download</Button>
      {open && (
        <div style={{
          position: 'absolute', right: 0, top: 'calc(100% + 6px)', width: 196, zIndex: 30,
          background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: 'var(--radius-lg)',
          boxShadow: 'var(--shadow-overlay)', padding: 6,
        }}>
          <Item icon={<window.Icon.docs size={15} />} label="Download as CSV" onClick={downloadCsv} />
          <Item icon={<window.Icon.docs size={15} />} label="Download as JSON" onClick={downloadJson} />
        </div>
      )}
    </div>
  );
}

function RunDetailScreen({ go, params }) {
  const { Card, MetricCard, StatusBadge, DataTable, Button } = DQ;
  const { PageHeader } = window;
  const run = (params && params.run) || RUNS[0];
