      'suite-check': W.CheckScreen,
      results: W.ResultsScreen,
      'run-detail': W.RunDetailScreen,
      profile: W.ProfileScreen,
      admin: W.AdminScreen,
      settings: W.SettingsScreen,
    };

    let content;
    if (nav.name === 'admin' && role !== 'Admin') {
      // Admin Control Center is gated — non-admins get a 403.
      content = (
        <ErrorState tone="client" code="403"
          title="Access denied"
          message="The Admin Control Center is restricted to workspace admins. Ask an admin to grant you the role, or head back to your dashboard."
          icon={<W.Icon.lock size={30} />}
          primaryAction={{ label: 'Back to Dashboard', onClick: () => go('dashboard') }}
          secondaryAction={{ label: 'View your Profile', onClick: () => go('profile') }} />
      );
    } else {
      const Screen = SCREENS[nav.name] || W.DashboardScreen;
      content = <Screen go={go} params={nav.params} />;
    }

    return (
      <AppShell route={nav.name} go={go} role={role} setRole={setRole}>
        {content}
      </AppShell>
    );
  }
  ReactDOM.createRoot(document.getElementById('root')).render(<App />);
</script>
</body>
</html>
