{"method":"get_file","path":"templates/app/ShareFlow.jsx","content":"// DataQ — Share Suite drawer. Invite people to a suite by email with a
// view/edit permission, and manage who already has access. Built on the
// design-system Drawer primitive. Exports window.ShareSuiteDrawer.
const DQshare = window.DataQDesignSystem_317fec;

const INITIAL_SHARES = [
  { name: 'Jane Doe', email: 'jane.doe@acme.com', perm: 'owner' },
  { name: 'Arijit Sen', email: 'arijit@acme.com', perm: 'edit' },
  { name: 'Mei Lin', email: 'mei.lin@acme.com', perm: 'view' },
];

function PermSelect({ value, onChange, disabled }) {
  return (
    <span style={{ position: 'relative', display: 'inline-block' }}>
      <select value={value} onChange={(e) => onChange(e.target.value)} disabled={disabled}
        style={{
          appearance: 'none', WebkitAppearance: 'none',
          height: 30, padding: '0 26px 0 10px', boxSizing: 'border-box',
          background: 'var(--bg-card)', border: '1px solid var(--border-input)', borderRadius: 'var(--radius)',
          fontFamily: 'var(--font-sans)', fontSize: 13, fontWeight: 500,
          color: disabled ? 'var(--text-muted)' : 'var(--text-primary)',
          cursor: disabled ? 'default' : 'pointer',
        }}>
        {disabled
          ? <option value="owner">Owner</option>
          : <React.Fragment><option value="view">Can view</option><option value="edit">Can edit</option><option value="remove">Remove</option></React.Fragment>}
      </select>
      {!disabled && (
        <span style={{ position: 'absolute', right: 9, top: '50%', transform: 'translateY(-50%)', pointerEvents: 'none', color: 'var(--text-muted)' }}>
          <window.Icon.down size={10} />
        </span>
      )}
    </span>
  );
}

function ShareSuiteDrawer({ open, onClose, suiteName }) {
  const { Drawer, Button, Avatar } = DQshare;
  if (!Drawer) return null;
  const [email, setEmail] = React.useState('');
  const [perm, setPerm] = React.useState('view');
  const [shares, setShares] = React.useState(INITIAL_SHARES);
  React.useEffect(() => { if (open) { setEmail(''); setPerm('view'); setShares(INITIAL_SHARES); } }, [open]);

  const addShare = () => {
    const v = email.trim();
    if (!v) return;
    const name = v.split('@')[0].split(/[.\-_]/).map((p) => p.charAt(0).toUpperCase() + p.slice(1)).join(' ');
    setShares((prev) => [...prev, { name, email: v, perm }]);
    setEmail('');
    setPerm('view');
  };

  const changePerm = (idx, value) => {
    if (value === 'remove') { setShares((prev) => prev.filter((_, i) => i !== idx)); return; }
    setShares((prev) => prev.map((s, i) => (i === idx ? { ...s, perm: value } : s)));
  };

  const footer = (
    <React.Fragment>
      <Button variant="secondary" onClick={onClose}>Done</Button>
      <Button variant="primary" iconLeft={<window.Icon.share size={14} />} onClick={onClose}>Share</Button>
    </React.Fragment>
  );

  return (
    <Drawer open={open} onClose={onClose} width={500}
      title="Share suite" subtitle={suiteName} footer={footer}>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
        {/* Suite name banner */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 14px', background: 'var(--bg-subtle)', border: '1px solid var(--border)', borderRadius: 'var(--radius)' }}>
          <div style={{ width: 34, height: 34, borderRadius: 8, flex: 'none', background: 'var(--ink)', color: 'var(--indigo-300)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>{React.createElement(window.Icon.suites, { size: 18 })}</div>
          <div style={{ minWidth: 0 }}>
            <div style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)' }}>{suiteName}</div>
            <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>{shares.length} {shares.length === 1 ? 'person has' : 'people have'} access</div>
          </div>
        </div>

        {/* Share with */}
        <div>
          <div style={{ fontSize: 13, fontWeight: 600, color: 'var(--text-primary)', marginBottom: 8 }}>Share with</div>
          <div style={{ display: 'flex', gap: 8, alignItems: 'stretch' }}>
            <span style={{ flex: 1, display: 'flex', alignItems: 'center', gap: 8, height: 40, padding: '0 12px', background: 'var(--bg-card)', border: '1px solid var(--border-input)', borderRadius: 'var(--radius)' }}>
              <window.Icon.user size={15} style={{ color: 'var(--text-muted)', flex: 'none' }} />
              <input value={email} onChange={(e) => setEmail(e.target.value)} placeholder="name@acme.com"
                onKeyDown={(e) => { if (e.key === 'Enter') addShare(); }}
                style={{ flex: 1, border: 'none', outline: 'none', background: 'transparent', fontFamily: 'var(--font-sans)', fontSize: 14, color: 'var(--text-primary)', minWidth: 0 }} />
            </span>
            <PermSelect value={perm} onChange={setPerm} />
          </div>
          <div style={{ marginTop: 8 }}>
            <Button variant="secondary" size="sm" iconLeft={<window.Icon.plus size={13} />} onClick={addShare}>Add person</Button>
          </div>
        </div>

        {/* People with access */}
        <div>
          <div style={{ fontSize: 12, fontWeight: 600, letterSpacing: '.04em', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: 10 }}>People with access</div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
            {shares.map((sh, i) => (
              <div key={sh.email} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '8px 0' }}>
                <Avatar name={sh.name} size={34} tone={sh.perm === 'owner' ? 'indigo' : 'gray'} />
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)' }}>{sh.name}{sh.perm === 'owner' && <span style={{ fontWeight: 500, color: 'var(--text-muted)' }}> (you)</span>}</div>
                  <div style={{ fontSize: 12, color: 'var(--text-muted)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{sh.email}</div>
                </div>
                <PermSelect value={sh.perm} disabled={sh.perm === 'owner'} onChange={(v) => changePerm(i, v)} />
              </div>
            ))}
          </div>
        </div>
      </div>
    </Drawer>
  );
}

